// The debounce function limits the rate at which a function can fire.
function debounce(func, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
      func.apply(this, args);
    }, delay);
  };
}

// Example usage:

function handleInputChange(event) {
  console.log('Input changed:', event.target.value);
  // In a real application, this might trigger an API call for autocomplete suggestions.
}

const debouncedInputChangeHandler = debounce(handleInputChange, 300); // Delay of 300ms

//  Now, attach debouncedInputChangeHandler to an input's 'input' event:
